using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers see all, customers see their own)
        group.MapGet("/", async (ApplicationDbContext db, UserManager<ApplicationUser> userManager, HttpContext http) =>
        {
            var user = await userManager.GetUserAsync(http.User);
            if (user is null) return Results.Unauthorized();

            IQueryable<Shipment> query = db.Shipments;
            if (!user.IsDispatcher)
            {
                query = query.Where(s => s.CustomerId == user.Id);
            }

            var shipments = await query.OrderByDescending(s => s.ShippedDate).ToListAsync();
            return Results.Ok(shipments.Select(MapToDto));
        });

        // Get single shipment
        group.MapGet("/{id:int}", async (int id, ApplicationDbContext db, UserManager<ApplicationUser> userManager, HttpContext http) =>
        {
            var user = await userManager.GetUserAsync(http.User);
            if (user is null) return Results.Unauthorized();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            if (!user.IsDispatcher && shipment.CustomerId != user.Id)
                return Results.Forbid();

            return Results.Ok(MapToDto(shipment));
        });

        // Track by tracking number (public)
        app.MapGet("/api/shipments/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null) return Results.NotFound();
            return Results.Ok(MapToDto(shipment));
        }).RequireAuthorization();

        // Create shipment (dispatchers only)
        group.MapPost("/", async (CreateShipmentRequest request, ApplicationDbContext db, UserManager<ApplicationUser> userManager, HttpContext http) =>
        {
            var user = await userManager.GetUserAsync(http.User);
            if (user is null) return Results.Unauthorized();
            if (!user.IsDispatcher) return Results.Forbid();

            var shipment = new Shipment
            {
                TrackingNumber = request.TrackingNumber,
                Origin = request.Origin,
                Destination = request.Destination,
                Status = ShipmentStatus.Pending,
                ShippedDate = DateTime.UtcNow,
                EstimatedDelivery = request.EstimatedDelivery,
                RecipientName = request.RecipientName,
                SenderName = request.SenderName,
                WeightKg = request.WeightKg,
                Notes = request.Notes ?? string.Empty,
                CustomerId = request.CustomerId
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", MapToDto(shipment));
        });

        // Update shipment status (dispatchers only)
        group.MapPut("/{id:int}/status", async (int id, UpdateStatusRequest request, ApplicationDbContext db, UserManager<ApplicationUser> userManager, HttpContext http) =>
        {
            var user = await userManager.GetUserAsync(http.User);
            if (user is null) return Results.Unauthorized();
            if (!user.IsDispatcher) return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = (ShipmentStatus)request.Status;
            if (shipment.Status == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.Ok(MapToDto(shipment));
        });

        // Update shipment (dispatchers only)
        group.MapPut("/{id:int}", async (int id, UpdateShipmentRequest request, ApplicationDbContext db, UserManager<ApplicationUser> userManager, HttpContext http) =>
        {
            var user = await userManager.GetUserAsync(http.User);
            if (user is null) return Results.Unauthorized();
            if (!user.IsDispatcher) return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Destination = request.Destination;
            shipment.EstimatedDelivery = request.EstimatedDelivery;
            shipment.Notes = request.Notes ?? string.Empty;
            shipment.WeightKg = request.WeightKg;

            await db.SaveChangesAsync();
            return Results.Ok(MapToDto(shipment));
        });

        // Delete shipment (dispatchers only)
        group.MapDelete("/{id:int}", async (int id, ApplicationDbContext db, UserManager<ApplicationUser> userManager, HttpContext http) =>
        {
            var user = await userManager.GetUserAsync(http.User);
            if (user is null) return Results.Unauthorized();
            if (!user.IsDispatcher) return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            db.Shipments.Remove(shipment);
            await db.SaveChangesAsync();
            return Results.NoContent();
        });
    }

    private static object MapToDto(Shipment s) => new
    {
        s.Id,
        s.TrackingNumber,
        s.Origin,
        s.Destination,
        Status = (int)s.Status,
        StatusName = s.Status.ToString(),
        s.ShippedDate,
        s.EstimatedDelivery,
        s.ActualDelivery,
        s.RecipientName,
        s.SenderName,
        s.WeightKg,
        s.Notes
    };
}

public record CreateShipmentRequest(
    string TrackingNumber,
    string Origin,
    string Destination,
    DateTime EstimatedDelivery,
    string RecipientName,
    string SenderName,
    double WeightKg,
    string? Notes,
    string? CustomerId);

public record UpdateStatusRequest(int Status);

public record UpdateShipmentRequest(
    string Destination,
