                new() { TrackingNumber = "TRK-002-2026", Origin = "Tokyo, Japan", Destination = "Sydney, Australia", Status = ShipmentStatus.PickedUp, ShippedDate = DateTime.UtcNow.AddDays(-1), EstimatedDelivery = DateTime.UtcNow.AddDays(6), RecipientName = "Jane Doe", SenderName = "Tech Industries", WeightKg = 3.2 },
                new() { TrackingNumber = "TRK-003-2026", Origin = "Berlin, Germany", Destination = "São Paulo, Brazil", Status = ShipmentStatus.OutForDelivery, ShippedDate = DateTime.UtcNow.AddDays(-7), EstimatedDelivery = DateTime.UtcNow, RecipientName = "Carlos Silva", SenderName = "Euro Logistics", WeightKg = 25.0 },
