                new() { TrackingNumber = "TRK-005-2026", Origin = "Mumbai, India", Destination = "Dubai, UAE", Status = ShipmentStatus.Pending, ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(3), RecipientName = "Ahmed Hassan", SenderName = "Spice Exports", WeightKg = 50.0 },
            };

            db.Shipments.AddRange(shipments);
            await db.SaveChangesAsync();
        }
    }
}

