@page "/shipments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject HttpClient Http

<PageTitle>Shipment Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="mb-3 d-flex gap-2 flex-wrap align-items-end">
    <div>
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="statusFilter">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@((int)s)">@s</option>
            }
        </select>
    </div>
    <div>
        <label class="form-label">Search</label>
        <input type="text" class="form-control" placeholder="Tracking # or destination..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="createShipment">
                <DataAnnotationsValidator />
                <div class="row g-2">
                    <div class="col-md-3">
                        <label class="form-label">Tracking #</label>
                        <InputText class="form-control" @bind-Value="newShipment.TrackingNumber" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Est. Delivery</label>
                        <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Recipient</label>
                        <InputText class="form-control" @bind-Value="newShipment.RecipientName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Sender</label>
                        <InputText class="form-control" @bind-Value="newShipment.SenderName" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="newShipment.WeightKg" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="newShipment.Notes" />
                    </div>
                </div>
                <div class="mt-2">
                    <button type="submit" class="btn btn-success">Create</button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
                <ValidationSummary />
            </EditForm>
        </div>
    </div>
}

@if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Recipient</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.ShippedDate.ToString("MMM dd, yyyy")</td>
                        <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>@shipment.RecipientName</td>
                        <td>
                            <div class="btn-group btn-group-sm">
                                <select class="form-select form-select-sm" style="width:auto"
                                        value="@((int)shipment.Status)"
                                        @onchange="(e) => UpdateStatus(shipment, e)">
                                    @foreach (var s in Enum.GetValues<ShipmentStatus>())
                                    {
                                        <option value="@((int)s)">@s</option>
                                    }
                                </select>
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => DeleteShipment(shipment.Id)">✕</button>
                            </div>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string statusFilter = "";
    private string searchTerm = "";
    private bool showCreateForm;
    private string? errorMessage;
    private CreateShipmentModel newShipment = new();

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(statusFilter) || (int)s.Status == int.Parse(statusFilter)) &&
            (string.IsNullOrEmpty(searchTerm) ||
             s.TrackingNumber.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
             s.Destination.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)));

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
            errorMessage = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private void ShowCreateForm()
    {
        newShipment = new CreateShipmentModel { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
        showCreateForm = true;
    }

    private async Task CreateShipment()
    {
        try
        {
            var response = await Http.PostAsJsonAsync("/api/shipments", new
            {
                newShipment.TrackingNumber,
                newShipment.Origin,
                newShipment.Destination,
                newShipment.EstimatedDelivery,
                newShipment.RecipientName,
                newShipment.SenderName,
                newShipment.WeightKg,
                newShipment.Notes,
                CustomerId = (string?)null
            });

            if (response.IsSuccessStatusCode)
            {
                showCreateForm = false;
                await LoadShipments();
            }
            else
            {
                errorMessage = $"Failed to create shipment: {response.StatusCode}";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var status))
        {
            try
            {
                var response = await Http.PutAsJsonAsync($"/api/shipments/{shipment.Id}/status", new { Status = status });
                if (response.IsSuccessStatusCode)
                    await LoadShipments();
                else
                    errorMessage = $"Failed to update status: {response.StatusCode}";
            }
            catch (Exception ex)
            {
                errorMessage = $"Error: {ex.Message}";
            }
        }
    }

    private async Task DeleteShipment(int id)
    {
        try
        {
            var response = await Http.DeleteAsync($"/api/shipments/{id}");
            if (response.IsSuccessStatusCode)
                await LoadShipments();
            else
                errorMessage = $"Failed to delete: {response.StatusCode}";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private class CreateShipmentModel
    {
        public string TrackingNumber { get; set; } = "";
        public string Origin { get; set; } = "";
        public string Destination { get; set; } = "";
        public DateTime EstimatedDelivery { get; set; } = DateTime.UtcNow.AddDays(7);
        public string RecipientName { get; set; } = "";
        public string SenderName { get; set; } = "";
        public double WeightKg { get; set; }
        public string Notes { get; set; } = "";
    }
}

